sql:
SELECT description
FROM fpga_designs
WHERE status = 'In Review';

SELECT created_by, COUNT(design_id) AS design_count
FROM fpga_designs
GROUP BY created_by;

SELECT fifo_type
FROM fifo_configurations
WHERE status = 'Draft';

SELECT COUNT(*) 
FROM fifo_configurations
WHERE status = 'Active';

SELECT fifo_type
FROM fifo_configurations
WHERE config_id = 1;

SELECT status, COUNT(*) as config_count
FROM fifo_configurations
GROUP BY status;

SELECT COUNT(*) AS total_changes
FROM design_history
WHERE change_date = '2023-05-02';

SELECT design_id, MAX(change_date) AS last_change_date, change_type
FROM design_history
GROUP BY design_id, change_type;

SELECT config_id, channel_id, created_by
FROM fifo_channel_configs
WHERE status = 'Active';

SELECT COUNT(*) 
FROM fpga_designs 
WHERE created_by = 0;

